from typing import List

class SegmentTreeNode:
    def __init__(self, l, r):
        self.l = l
        self.r = r
        self.left = None
        self.right = None
        self.count = 0  # count of alternating groups in this segment

class SegmentTree:
    def __init__(self, data):
        self.n = len(data)
        self.data = data
        self.root = self.build(0, self.n - 1)

    def build(self, l, r):
        node = SegmentTreeNode(l, r)
        if l == r:
            node.count = 0  # no group of size > 1 in a single tile
            return node
        mid = (l + r) // 2
        node.left = self.build(l, mid)
        node.right = self.build(mid + 1, r)
        node.count = node.left.count + node.right.count
        return node

    def update(self, index, value):
        self._update(self.root, index, value)

    def _update(self, node, index, value):
        if node.l == node.r == index:
            node.count = 0
            return
        if index <= node.left.r:
            self._update(node.left, index, value)
        else:
            self._update(node.right, index, value)
        # Recompute count based on children
        node.count = node.left.count + node.right.count

    def query(self, size):
        return self._query(self.root, size)

    def _query(self, node, size):
        if node.r - node.l + 1 < size:
            return 0
        if node.l == node.r:
            return 0
        if node.left.r - node.left.l + 1 >= size:
            left_count = self._query(node.left, size)
        else:
            left_count = 0
        if node.right.r - node.right.l + 1 >= size:
            right_count = self._query(node.right, size)
        else:
            right_count = 0
        return left_count + right_count

class Solution:
    def numberOfAlternatingGroups(self, colors: List[int], queries: List[List[int]]) -> List[int]:
        n = len(colors)
        # Build the segment tree
        st = SegmentTree(colors)
        result = []

        for query in queries:
            if query[0] == 1:
                size = query[1]
                count = st.query(size)
                result.append(count)
            else:
                index = query[1]
                color = query[2]
                st.update(index, color)
        return result
